import { EventManager } from '../../events/event-manager';
import { detachevent } from '../../events/eventActions';

export class LegendEventManager extends EventManager {
    updateSelectionManager(data) {
        this.selectionManager.point = data;
    }

    detachListeners(namespace, mouseHandlers = {}, touchHandlers = {}) {
        let manager = this,
            { tracker } = manager;

        if (!tracker || tracker.empty()) {
            return;
        }

        detachevent(tracker, namespace, mouseHandlers);
        detachevent(tracker, namespace, touchHandlers);
    }
}
